// Copy one test-case payload at a time before sending. TC01 is active by default.

// TC01 — 201 Created: complete direct student; admissionDocsId remains null; guardian and academic record are created.
{
  "schoolId": "6a474d2517e9c40cf971ccc2",
  "admissionNo": "TC-STUDENT-{{$timestamp}}",
  "name": "TC1 Complete Direct Student",
  "dob": "2015-06-19",
  "gender": "MALE",
  "bloodGroup": "AB+",
  "documents": ["birth-certificate.pdf", "address-proof.pdf"],
  "status": "ACTIVE",
  "admissionDate": "2026-07-22",
  "guardians": [
    {
      "name": "TC1 Parent {{$timestamp}}",
      "relation": "MOTHER",
      "phone": "+61-400-555-666",
      "email": "tc1.{{$timestamp}}@example.com",
      "primary": true,
      "emergencyContact": true
    }
  ],
  "currentAcademicRecord": {
    "academicYear": "2026-2027",
    "studentNo": "TC-STD-{{$timestamp}}",
    "rollNo": "9C-03",
    "sectionNo": "C",
    "status": "ACTIVE"
  }
}

// TC02 — 201 Created: minimum required fields; no guardian or academic record.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "TC-MIN-{{$timestamp}}", "name": "TC2 Minimal Student" }

// TC03 — 201 Created: creates and links multiple new guardians.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "TC-GUARDIANS-{{$timestamp}}", "name": "TC3 Guardians", "guardians": [{ "name": "TC3 Mother", "relation": "MOTHER" }, { "name": "TC3 Father", "relation": "FATHER" }] }

// TC04 — 201 Created: links an existing same-school guardian.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "TC-EXISTING-GUARDIAN-{{$timestamp}}", "name": "TC4 Existing Guardian", "guardians": [{ "guardianDocsId": "SAME_SCHOOL_GUARDIAN_ID", "relation": "FATHER" }] }

// TC05 — 201 Created: duplicate guardian details are de-duplicated to one link.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "TC-DEDUPE-{{$timestamp}}", "name": "TC5 Dedupe", "guardians": [{ "name": "TC5 Parent", "email": "tc5@example.com" }, { "name": "TC5 Parent", "email": "tc5@example.com" }] }

// TC06 — 201 Created: academic record from top-level academicYear/classDocId/sectionNo/rollNo.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "TC-TOP-ACADEMIC-{{$timestamp}}", "name": "TC6 Top Academic", "academicYear": "2026-2027", "classDocId": "SAME_SCHOOL_CLASS_ID", "sectionNo": "A", "rollNo": "12" }

// TC07 — 201 Created: client admissionDocsId is ignored for direct creation.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "TC-NO-LINK-{{$timestamp}}", "name": "TC7 No Admission Link", "admissionDocsId": "SHOULD_NOT_BE_STORED" }

// TC08 — 400 Bad Request: empty body; required schoolId, admissionNo, and name are missing.
// {}

// TC09 — 400 Bad Request: missing or blank schoolId.
// { "admissionNo": "TC-MISSING-SCHOOL", "name": "TC9 Missing School" }

// TC10 — 400 Bad Request: missing or blank admissionNo.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "   ", "name": "TC10 Blank Admission Number" }

// TC11 — 400 Bad Request: missing or blank name.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "TC-MISSING-NAME", "name": "   " }

// TC12 — 409 Conflict: reuse an existing admissionNo.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "EXISTING_ADMISSION_NO", "name": "TC12 Duplicate Admission Number" }

// TC13 — 404 Not Found: non-existent school.
// { "schoolId": "000000000000000000000000", "admissionNo": "TC-NO-SCHOOL", "name": "TC13 Missing School" }

// TC14 — 400 Bad Request: guardian has neither guardianDocsId nor name.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "TC-EMPTY-GUARDIAN", "name": "TC14 Empty Guardian", "guardians": [{ "relation": "MOTHER" }] }

// TC15 — 400 Bad Request: invalid guardian email.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "TC-BAD-EMAIL", "name": "TC15 Invalid Email", "guardians": [{ "name": "Parent", "email": "not-an-email" }] }

// TC16 — 404 Not Found: guardianDocsId does not exist.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "TC-NO-GUARDIAN", "name": "TC16 Missing Guardian", "guardians": [{ "guardianDocsId": "000000000000000000000000", "relation": "FATHER" }] }

// TC17 — 400 Bad Request: guardian belongs to another school.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "TC-WRONG-GUARDIAN-SCHOOL", "name": "TC17 Wrong Guardian School", "guardians": [{ "guardianDocsId": "OTHER_SCHOOL_GUARDIAN_ID", "relation": "FATHER" }] }

// TC18 — 400 Bad Request: invalid gender/status/relation enum.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "TC-BAD-ENUM", "name": "TC18 Invalid Enum", "gender": "INVALID" }

// TC19 — 400 Bad Request: invalid DOB or admissionDate; use non-ISO date.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "TC-BAD-DATE", "name": "TC19 Invalid Date", "dob": "19-06-2015" }

// TC20 — 404/400: missing or cross-school classDocId; operation must roll back.
// { "schoolId": "6a474d2517e9c40cf971ccc2", "admissionNo": "TC-BAD-CLASS", "name": "TC20 Invalid Class", "currentAcademicRecord": { "academicYear": "2026-2027", "classDocId": "000000000000000000000000" } }

// TC21 — 400 Bad Request: malformed JSON. Remove the closing brace from any payload.

// Replace the admission ID in the URL. Copy one test-case payload at a time. TC01 is active by default.

// TC01 — 201 Created: ID-only conversion; admission data is copied and admission/inquiry become CONFIRMED.
{}

// TC02 — 201 Created: request fields override copied name, DOB, and gender.
// { "name": "TC2 Corrected Name", "dob": "2015-05-10", "gender": "FEMALE" }

// TC03 — 201 Created: adds/corrects documents, photo, blood group, and medical remarks.
// { "bloodGroup": "O+", "photoUrl": "https://example.com/photo.jpg", "documents": ["corrected-birth-certificate.pdf"], "medicalRemark": ["Peanut allergy"] }

// TC04 — 201 Created: merges admission guardians and adds a new guardian.
// { "guardians": [{ "name": "Meera Nair", "relation": "MOTHER", "address": "12 Corrected Street" }, { "name": "Raj Nair", "relation": "FATHER", "phone": "+61-400-333-444" }] }

// TC05 — 201 Created: links an existing same-school guardian with guardianDocsId.
// { "guardians": [{ "guardianDocsId": "SAME_SCHOOL_GUARDIAN_ID", "relation": "LEGAL_GUARDIAN", "primary": true }] }

// TC06 — 201 Created: creates a nested academic record and stores currentAcademicRecordDocsId.
// { "currentAcademicRecord": { "academicYear": "2026-2027", "studentNo": "TC-REC-{{$timestamp}}", "rollNo": "18", "classDocId": "SAME_SCHOOL_CLASS_ID", "sectionNo": "B", "status": "ACTIVE" } }

// TC07 — 201 Created: creates academic placement from top-level fields.
// { "academicYear": "2026-2027", "studentNo": "TC-TOP-{{$timestamp}}", "rollNo": "22", "classDocId": "SAME_SCHOOL_CLASS_ID", "sectionNo": "A" }

// TC08 — 201 Created: supplied schoolId is ignored; admission school is authoritative.
// { "schoolId": "DIFFERENT_SCHOOL_ID" }

// TC09 — 201 Created: exact source admissionNo may be repeated; a different value is rejected.
// { "admissionNo": "EXACT_ADMISSION_NUMBER_FROM_SOURCE" }

// TC10 — 404 Not Found: non-existent admission ID in URL.
// {}

// TC11 — 409 Conflict: run TC01, then repeat the same URL; a second student is prevented.
// {}

// TC12 — 400 Bad Request: source admission has REJECTED status.
// {}

// TC13 — 400 Bad Request: admissionNo differs from source admission.
// { "admissionNo": "DIFFERENT-ADMISSION-NUMBER" }

// TC14 — 404 Not Found: source admission school no longer exists.
// {}

// TC15 — 400 Bad Request: admission school has reached maxStudents.
// {}

// TC16 — 400 Bad Request: guardian has neither guardianDocsId nor name.
// { "guardians": [{ "relation": "MOTHER" }] }

// TC17 — 400 Bad Request: invalid guardian email.
// { "guardians": [{ "name": "Invalid Email Parent", "email": "not-an-email" }] }

// TC18 — 404 Not Found: guardianDocsId does not exist.
// { "guardians": [{ "guardianDocsId": "000000000000000000000000", "relation": "FATHER" }] }

// TC19 — 400 Bad Request: guardian belongs to another school.
// { "guardians": [{ "guardianDocsId": "OTHER_SCHOOL_GUARDIAN_ID", "relation": "FATHER" }] }

// TC20 — 404/400: missing or cross-school classDocId; transaction must roll back.
// { "currentAcademicRecord": { "academicYear": "2026-2027", "classDocId": "000000000000000000000000" } }

// TC21 — 400 Bad Request: invalid gender/status/relation/date/academic status enum or format.
// { "gender": "INVALID" }

// TC22 — 400 Bad Request: malformed JSON. Remove the closing brace from any payload.

// After TC12, TC15, or TC16-TC20 fails, GET the admission and inquiry: studentDocsId must remain null, and inquiry status must not be CONFIRMED.
